class Solution {
public:
    double knightProbability(int n, int k, int r, int c) {
        vector<vector<double>> dp(n,vector<double>(n)); dp[r][c]=1;
        int mv[8][2]={{-2,-1},{-2,1},{-1,-2},{-1,2},{2,-1},{2,1},{1,-2},{1,2}};
        for(int t=0;t<k;t++){
            vector<vector<double>> nd(n,vector<double>(n));
            for(int i=0;i<n;i++) for(int j=0;j<n;j++) if(dp[i][j])
                for(auto& m:mv){ int ni=i+m[0],nj=j+m[1]; if(ni>=0&&ni<n&&nj>=0&&nj<n) nd[ni][nj]+=dp[i][j]/8.0; }
            dp=nd;
        }
        double s=0; for(auto& row:dp) s+=accumulate(row.begin(),row.end(),0.0); return s;
    }
};

